    "Absorb Elements": {"l": 1, "s": "A", "t": "1rea", "r": "se", "c": "s", "d": "1ro", "st": [], "dmg": [], "area": [], "cls": [], "rit": null, "conc": null},
    "Acid Splash": {"l": 0, "s": "C", "t": "1act", "r": "60fe", "c": "v,s", "d": "instant", "st": ["dexterity"], "dmg": ["acid"], "area": ["MT", "ST"], "cls": [], "rit": null, "conc": null},
    "Aganazzar's Scorcher": {"l": 2, "s": "V", "t": "1act", "r": "30fe", "c": "v,s,m", "d": "instant", "st": ["dexterity"], "dmg": ["fire"], "area": ["L"], "cls": [], "rit": null, "conc": null},
    "Aid": {"l": 2, "s": "A", "t": "1act", "r": "30fe", "c": "v,s,m", "d": "8ho", "st": [], "dmg": [], "area": ["MT"], "cls": [], "rit": null, "conc": null},
