/* ═══════════════════════════════════════════════════════════════════
   KB HELPER FUNCTIONS — Enrich AI responses with 5etools data
   ═══════════════════════════════════════════════════════════════════ */

KB.school_map = {
  A:'Abjuration', C:'Conjuration', D:'Divination', E:'Enchantment',
  I:'Illusion', N:'Necromancy', T:'Transmutation', V:'Evocation'
};

KB.lookupSpell = function(name) { return this.spells[name] || null; };

KB.lookupMonster = function(name) { return this.monsters[name] || null; };

KB.lookupItem = function(name) { return this.items[name] || null; };

KB.formatSpell = function(name) {
  const s = this.lookupSpell(name);
  if (!s) return '';
  const school = this.school_map[s.s] || s.s;
  const lvl = s.l === 0 ? 'Cantrip' : `Lv ${s.l}`;
  const conc = s.conc ? ' (Concentration)' : '';
  const rit = s.rit ? ' (Ritual)' : '';
  const cls = s.cls?.length ? ` — ${s.cls.slice(0,4).join(', ')}` : '';
  const save = s.st?.length ? ` • Save: ${s.st.join('/')}` : '';
  const dmg = s.dmg?.length ? ` • Damage: ${s.dmg.join('/')}` : '';
  return `**${name}** (${lvl}, ${school})\nCast: ${s.t || '?'} | Range: ${s.r || '?'} | Components: ${s.c || '?'}`
    + ` | Duration: ${s.d || '?'}${conc}${rit}${cls}${save}${dmg}`;
};

KB.summarizeMonster = function(name) {
  const m = this.lookupMonster(name);
  if (!m) return '';
  const stats = m.ab ? `STR ${m.ab[0]}  DEX ${m.ab[1]}  CON ${m.ab[2]}  INT ${m.ab[3]}  WIS ${m.ab[4]}  CHA ${m.ab[5]}` : '';
  return `**${name}** (CR ${m.cr}, ${m.hp} HP, AC ${m.ac})\n${stats}\nSpeed: ${m.sp || '?'}\nSense: ${m.sense || '—'} | Languages: ${m.lang ? m.lang.slice(0,4).join(', ') : '—'} | Environments: ${m.env?.slice(0,5).join(', ') || '—'}`;
};

KB.formatItem = function(name) {
  const i = this.lookupItem(name);
  if (!i) return '';
  if (i.t === 'S') return `**${name}** (Shield, +${i.ac} AC)`;
  if (i.t === 'LA') return `**${name}** (Light Armour, AC ${i.ac})`;
  if (i.t === 'MA') return `**${name}** (Medium Armour, AC ${i.ac})`;
  if (i.t === 'HA') return `**${name}** (Heavy Armour, AC ${i.ac})`;
  const rng = i.r ? `, Range ${i.r}` : '';
  const dmg = i.d1 ? ` (${i.d1}${i.d2 ? '/' + i.d2 : ''} ${i.dt || ''})` : '';
  const props = i.p ? ` [${i.p.join(', ')}]` : '';
  const type = {'M':'Melee','R':'Ranged'}[i.t] || i.t;
  return `**${name}** (${type}${dmg}${rng}${props})`;
};

